import{_ as a,a as t,b as n,c as o,d as l}from"./chunks/编辑配置.T0puvWjh.js";import{_ as r,o as d,c as i,a2 as s}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Een Telegram-kanaal toevoegen","description":"","frontmatter":{},"headers":[],"relativePath":"nl-NL/upload/telegram.md","filePath":"nl-NL/upload/telegram.md","lastUpdated":1781962217000}'),h={name:"nl-NL/upload/telegram.md"};function c(p,e,g,b,m,k){return d(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="een-telegram-kanaal-toevoegen" tabindex="-1">Een Telegram-kanaal toevoegen <a class="header-anchor" href="#een-telegram-kanaal-toevoegen" aria-label="Permalink to &quot;Een Telegram-kanaal toevoegen&quot;">​</a></h1><h2 id="wat-je-vooraf-nodig-hebt" tabindex="-1">Wat je vooraf nodig hebt <a class="header-anchor" href="#wat-je-vooraf-nodig-hebt" aria-label="Permalink to &quot;Wat je vooraf nodig hebt&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Vereiste</th><th>Doel</th></tr></thead><tbody><tr><td>Telegram-account</td><td>Voor het maken van de bot en het opslagkanaal.</td></tr><tr><td><code>@BotFather</code></td><td>Voor het maken van een Telegram-bot.</td></tr><tr><td>Telegram-kanaal</td><td>De uiteindelijke opslagplek voor bestanden.</td></tr><tr><td><code>@userinfobot</code></td><td>Voor het opzoeken van de <code>Chat ID</code> van het kanaal.</td></tr></tbody></table><h2 id="waar-je-het-toevoegt" tabindex="-1">Waar je het toevoegt <a class="header-anchor" href="#waar-je-het-toevoegt" aria-label="Permalink to &quot;Waar je het toevoegt&quot;">​</a></h2><ol><li>Open Systeeminstellingen.</li><li>Ga naar Uploadinstellingen.</li><li>Klik rechtsboven op Kanaal toevoegen.</li><li>Selecteer <code>Telegram</code>.</li></ol><h2 id="veldreferentie" tabindex="-1">Veldreferentie <a class="header-anchor" href="#veldreferentie" aria-label="Permalink to &quot;Veldreferentie&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Veld</th><th>Functie</th><th>Verplicht</th></tr></thead><tbody><tr><td>Kanaalnaam</td><td>Een herkenbare naam, bijvoorbeeld <code>Telegram Primary</code>.</td><td>Ja</td></tr><tr><td>Actief</td><td>Schakelt dit kanaal in of uit.</td><td>Aanbevolen</td></tr><tr><td>Bot Token</td><td>Het token van je Telegram-bot.</td><td>Ja</td></tr><tr><td>Session ID (Chat ID)</td><td>De ID van het Telegram-kanaal.</td><td>Ja</td></tr><tr><td>Relay Proxy URL (optioneel)</td><td>Alleen gebruiken als Telegram-toegang instabiel is. Vul de volledige proxy-URL in, inclusief <code>https://</code>.</td><td>Nee</td></tr><tr><td>Opmerking</td><td>Notities voor later beheer.</td><td>Nee</td></tr></tbody></table><h2 id="instelstappen" tabindex="-1">Instelstappen <a class="header-anchor" href="#instelstappen" aria-label="Permalink to &quot;Instelstappen&quot;">​</a></h2><h3 id="_1-maak-een-telegram-bot" tabindex="-1">1. Maak een Telegram-bot <a class="header-anchor" href="#_1-maak-een-telegram-bot" aria-label="Permalink to &quot;1. Maak een Telegram-bot&quot;">​</a></h3><ol><li>Open Telegram en zoek naar <code>@BotFather</code>.</li><li>Open de chat en klik op <code>Start</code>.</li><li>Stuur <code>/newbot</code>.</li><li>Volg de aanwijzingen en vul een weergavenaam voor de bot in.</li><li>Vul daarna een botgebruikersnaam in. Deze moet meestal eindigen op <code>bot</code>.</li><li>Na het aanmaken stuurt <code>@BotFather</code> een bot token terug.</li></ol><p>Dit token vul je in ImgBed in als <code>Bot Token</code>.</p><p><img src="'+a+'" alt="Bot token bewaren" loading="lazy"></p><h3 id="_2-maak-een-kanaal" tabindex="-1">2. Maak een kanaal <a class="header-anchor" href="#_2-maak-een-kanaal" aria-label="Permalink to &quot;2. Maak een kanaal&quot;">​</a></h3><ol><li>Klik in Telegram op Nieuw kanaal.</li><li>Vul een kanaalnaam in.</li><li>Rond het aanmaken af.</li></ol><p>Zowel openbare als privékanalen kunnen worden gebruikt.</p><p><img src="'+t+'" alt="Kanaal maken" loading="lazy"></p><h3 id="_3-voeg-de-bot-toe-aan-het-kanaal" tabindex="-1">3. Voeg de bot toe aan het kanaal <a class="header-anchor" href="#_3-voeg-de-bot-toe-aan-het-kanaal" aria-label="Permalink to &quot;3. Voeg de bot toe aan het kanaal&quot;">​</a></h3><ol><li>Open het kanaal dat je net hebt gemaakt.</li><li>Open de kanaalinstellingen.</li><li>Voeg een lid of beheerder toe.</li><li>Zoek de gebruikersnaam van je bot.</li><li>Voeg de bot toe aan het kanaal.</li></ol><p>Voor de betrouwbaarste uploads geef je de bot beheerdersrechten.</p><p><img src="'+n+'" alt="Bot uitnodigen in het kanaal" loading="lazy"></p><h3 id="_4-haal-de-channel-id-op-met-user-info-get-id-idbot" tabindex="-1">4. Haal de Channel ID op met User Info - Get ID - IDbot <a class="header-anchor" href="#_4-haal-de-channel-id-op-met-user-info-get-id-idbot" aria-label="Permalink to &quot;4. Haal de Channel ID op met User Info - Get ID - IDbot&quot;">​</a></h3><ol><li>Zoek in Telegram naar <code>@userinfobot</code>. De weergavenaam is meestal <code>User Info - Get ID - IDbot</code>.</li><li>Open de chat en klik op <code>Start</code>.</li><li>Kies <code>Channel</code> uit de opties van de bot.</li><li>Selecteer in de berichtkiezer het doelkanaal en stuur het naar <code>@userinfobot</code>.</li><li>Wanneer <code>@userinfobot</code> het resultaat terugstuurt, kopieer je het nummer bij <code>Id: -100...</code>.</li></ol><p>Het nummer dat begint met <code>-100</code> is de <code>Session ID (Chat ID)</code> die ImgBed nodig heeft.</p><p><img src="'+o+'" alt="Channel ID ophalen" loading="lazy"></p><h3 id="_5-vul-het-telegram-kanaal-in-imgbed-in" tabindex="-1">5. Vul het Telegram-kanaal in ImgBed in <a class="header-anchor" href="#_5-vul-het-telegram-kanaal-in-imgbed-in" aria-label="Permalink to &quot;5. Vul het Telegram-kanaal in ImgBed in&quot;">​</a></h3><p>Ga terug naar het configuratievenster en vul in:</p><table tabindex="0"><thead><tr><th>UI-veld</th><th>Waarde</th></tr></thead><tbody><tr><td>Channel Identifier</td><td>Een eigen kanaalnaam, bijvoorbeeld <code>TelegramPrimary</code>.</td></tr><tr><td>Actief</td><td>Aanbevolen.</td></tr><tr><td>Bot Token</td><td>Het token van <code>@BotFather</code>.</td></tr><tr><td>Session ID (Chat ID)</td><td>Het <code>-100...</code>-nummer dat <code>@userinfobot</code> teruggaf.</td></tr><tr><td>Relay Proxy URL (optioneel)</td><td>Alleen indien nodig, bijvoorbeeld <code>https://your-tg-proxy.example.com</code>.</td></tr><tr><td>Opmerking</td><td>Optionele notities.</td></tr></tbody></table><p>Klik op Opslaan wanneer je klaar bent.</p><p><img src="'+l+`" alt="Configuratie bewerken" loading="lazy"></p><h2 id="controleren" tabindex="-1">Controleren <a class="header-anchor" href="#controleren" aria-label="Permalink to &quot;Controleren&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Controle</th><th>Hoe je controleert</th></tr></thead><tbody><tr><td>Kanaalkaart verschijnt</td><td>Na opslaan moet in Uploadinstellingen een Telegram-kanaalkaart zichtbaar zijn.</td></tr><tr><td>Kanaal kan aan</td><td>De Actief-schakelaar blijft ingeschakeld.</td></tr><tr><td>Configuratie is opgeslagen</td><td>De detailweergave toont dat Bot Token en Chat ID zijn opgeslagen.</td></tr><tr><td>Upload werkt</td><td>Upload een testafbeelding en controleer of die in het doelkanaal van Telegram verschijnt.</td></tr></tbody></table><h2 id="snelle-checklist" tabindex="-1">Snelle checklist <a class="header-anchor" href="#snelle-checklist" aria-label="Permalink to &quot;Snelle checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Maak een bot met @BotFather</span></span>
<span class="line"><span>-&gt; Bewaar het Bot Token</span></span>
<span class="line"><span>-&gt; Maak een Telegram-kanaal</span></span>
<span class="line"><span>-&gt; Voeg de bot toe aan het kanaal en geef beheerdersrechten</span></span>
<span class="line"><span>-&gt; Zoek @userinfobot en kies Channel</span></span>
<span class="line"><span>-&gt; Stuur een bericht uit het kanaal door naar @userinfobot</span></span>
<span class="line"><span>-&gt; Kopieer de teruggegeven Id: -100...</span></span>
<span class="line"><span>-&gt; Vul Bot Token en Chat ID in ImgBed in</span></span>
<span class="line"><span>-&gt; Sla op en upload een testafbeelding</span></span></code></pre></div><h2 id="referenties" tabindex="-1">Referenties <a class="header-anchor" href="#referenties" aria-label="Permalink to &quot;Referenties&quot;">​</a></h2><ol><li>Telegram bots: <a href="https://core.telegram.org/bots" target="_blank" rel="noreferrer">https://core.telegram.org/bots</a></li><li>Telegram Bot API: <a href="https://core.telegram.org/bots/api" target="_blank" rel="noreferrer">https://core.telegram.org/bots/api</a></li></ol>`,35)])])}const _=r(h,[["render",c]]);export{v as __pageData,_ as default};
